endmodule

module request_fsm(input logic clk, rst_n, req, output logic busy);
  typedef enum logic {IDLE, BUSY} state_t; state_t state, next_state;
  always_comb begin
    case (state)
      IDLE: next_state = req ? BUSY : IDLE;
      BUSY: next_state = req ? BUSY : IDLE;
    endcase
  end
  always_ff @(posedge clk or negedge rst_n) if (!rst_n) state <= IDLE; else state <= next_state;
  assign busy = (state == BUSY);
endmodule

module lsb_serializer(input logic clk, rst_n, load, shift_en, input logic [7:0] data, output logic serial_out);
