module safe_fsm(input logic clk, rst_n, start, fault, output logic running);
  typedef enum logic [1:0] {IDLE, RUN, ERROR} state_t; state_t state, next_state;
  always_comb begin next_state = state; case (state) IDLE: if (start) next_state = RUN; RUN: if (fault) next_state = ERROR; ERROR: next_state = ERROR; default: next_state = ERROR; endcase end
  always_ff @(posedge clk or negedge rst_n) if (!rst_n) state <= IDLE; else state <= next_state;
  assign running = (state == RUN);
endmodule

